/**
 * Custom hook for loading disbursement services
 */

import { useQuery as useReactQuery } from '@tanstack/react-query';
import { disbursementService } from '@/features/disbursements/services';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import logger from '@/shared/utils/logger.js';

export const useDisbursementServices = () => {
  // Use React Query directly since we need a custom queryFn (not a simple endpoint)
  const { data: servicesResponse, isLoading } = useReactQuery({
    queryKey: queryKeys.disbursements.services(),
    queryFn: async () => {
      const response = await disbursementService.getAllServices();
      if (response.code === '00' && response.data) {
        return response.data;
      }
      return [];
    },
    staleTime: 5 * 60 * 1000,
    refetchOnWindowFocus: false,
    retry: 2,
  });

  const services = servicesResponse || [];
  const servicesByName = services.reduce((acc, service) => {
    if (service?.name) {
      acc[service.name.toString().toLowerCase().trim()] = service;
    }
    return acc;
  }, {});

  // Log service names to help diagnose env differences (dev vs staging naming)
  logger.debug('Disbursement services loaded', { serviceNames: services.map(s => s?.name) });

  const disbursementServiceId = servicesByName.disbursement?.id || servicesByName.disbursements?.id || null;
  const collectionServiceId = servicesByName.collection?.id || servicesByName.collections?.id || null;
  const settlementServiceId = servicesByName.settlement?.id || servicesByName.settlements?.id || null;

  return {
    services,
    disbursementServiceId,
    collectionServiceId,
    settlementServiceId,
    isLoading,
  };
};

